features.snippet:
module TopLevel (
  output wire uart_txd,
  input  wire clk
);
  MidLevel mid (
    .clk(clk),
    .data_out(txd_internal)
  );
  assign uart_txd = txd_internal;
endmodule

module MidLevel (
  output wire data_out,
  input  wire clk
);
  (* keep_hierarchy = "TRUE" *) LeafModule leaf (
    .clk(clk),
    .result(data_out)
  );
endmodule

module LeafModule (
  input  wire io_dataIn,
  output wire io_dataOut,
  input  wire clk,
  input  wire axiReset
);
  reg  io_dataOut_r;
  wire internal_sync_signal;
  assign internal_sync_signal = io_dataIn;
  always @(posedge clk) io_dataOut_r <= internal_sync_signal;
  assign io_dataOut = io_dataOut_r;
endmodule
